// Lazy-load highlightjs on intersection
const io = new IntersectionObserver((entries) => {
  if (entries.some(e => e.isIntersecting)) {
    import('highlight.js').then(({ default: hljs }) => hljs.highlightAll());
  }
}, { rootMargin: '200px' });
io.observe(document.querySelector('.brndle-code'));
